"use strict";function generateTemplate(){const e=document.getElementById("sel-grade").value,t=document.getElementById("sel-subject").value,a=document.getElementById("sel-q").value,n=document.getElementById("sel-week").value;if(!(e&&t&&a&&n))return void showToast("⚠ Select grade, subject, quarter and week first.");const s=buildHTML({grade:e,subject:t,q:a,week:n,comp:DB[e]?.data?.[t]?.[a]?.[n]||buildGeneric(e,t,a,n)});quill.clipboard.dangerouslyPasteHTML(s),autoSave(),showToast("✓ Template lesson plan generated!")}async function generateWithAI(){const e=document.getElementById("sel-grade").value,t=document.getElementById("sel-subject").value,a=document.getElementById("sel-q").value,n=document.getElementById("sel-week").value,s=document.getElementById("t-melc").value.trim();if(!e||!t||!a)return void showToast("⚠ Select grade, subject, and quarter first.");const i=ksOf(e),o=DB[e]?.data?.[t]?.[a]?.[n],r=o||buildGeneric(e,t,a,n),d=s||r.text,l=`Grade ${e} (${ksLabel(i)})`,c=document.getElementById("sel-tier").value,p=document.getElementById("tog-diverse").checked,m=document.getElementById("tog-lr").checked,u=document.getElementById("tog-values").checked,g=`You are a DepEd-certified curriculum designer in the Philippines writing an ILAW lesson plan under DO No. 016, s. 2026.\n\nContext:\n- Grade: ${l}\n- Key Stage: ${i}\n- Subject: ${t}\n- Quarter: Q${a}${n?`, Week ${n}`:""}\n- MELC: "${d}"\n- Emergency Tier: ${c}\n- Diverse Learners: ${p}\n- Low-Resource Environment: ${m}\n- Values Integration: ${u}\n\nWrite a COMPLETE and DETAILED ILAW lesson plan in HTML using the exact CSS classes provided.\n\nCRITICAL RULES:\n1. If Key Stage 1 (Grades 1–3): Do NOT include grading percentages or transmutation tables. Use PACE Form assessment only.\n2. If Key Stage 2–4: Include the WW/PT/ST grading table (20%/50%/30%) and the transmutation formula.\n3. Emergency tier "${c}": ${"normal"===c?"Standard classroom instruction.":"hinay"===c?"Include a Hinay hybrid section with Self-Learning Packet distribution notes.":"hinga"===c?"Replace classroom instruction with home-based modular procedures and 12-hour call-tree check-in protocol.":"Academic lessons are SUSPENDED. Replace instruction with full PFA / trauma-informed check-in procedures. Do not include academic content."}\n4. ${p?"Include a Diverse Learner Accommodations block (class lp-acc) with Key Stage-appropriate modifications.":""}\n5. ${m?"Add Low-Resource Environment alternatives (class lp-lr) replacing standard materials with local/recycled substitutes.":""}\n6. ${u?"Embed a Values Integration note connecting lesson content to national values (maka-Diyos, makatao, makakalikasan, makabansa).":""}\n\nUse these CSS classes for structure:\n- .lp-hdr (header block)\n- .lp-meta (metadata table)  \n- .lp-sh (section header: I, L, A, W)\n- .lp-ssh (subsection header)\n- .lp-body (body text)\n- .lp-obj (CPA objectives table with .ol class for label cells)\n- .lp-step (each flow step, with .lp-step-title inside)\n- .lp-dp (design principles note)\n- .lp-gt (grading table, if KS2+)\n- .lp-pace (PACE form table, if KS1)\n- .lp-acc (accommodation block)\n- .lp-em (emergency tier block)\n- .lp-lr (low-resource block)\n- .lp-sig (signature table)\n\nTeacher: ${document.getElementById("t-name").value||"[Teacher Name]"}\nSchool: ${document.getElementById("t-school").value||"[School Name]"}\nSection: ${document.getElementById("t-section").value||"[Section]"}\nDate: ${document.getElementById("t-date").value||(new Date).toISOString().split("T")[0]}\nTime: ${document.getElementById("t-time").value||"07:30"} | ${document.getElementById("t-dur").value||"60 mins"}\n\nWrite ONLY the HTML content. No markdown. No backticks. Start with the header div.`,h=document.getElementById("ai-status"),v=document.getElementById("ai-gen-btn"),b=["Claude is writing your lesson plan…","Scaffolding the objectives…","Building the learning flow…","Crafting assessment tasks…","Adding Ways Forward…"];let y=0;h.classList.add("active"),v.disabled=!0;const f=document.getElementById("ai-msg"),_=setInterval(()=>{f.textContent=b[y++%b.length]},2200);try{const s=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-6",max_tokens:4096,system:"You are an expert DepEd curriculum writer. Output only valid HTML with inline styles and the CSS classes provided. No markdown, no explanation, no backticks.",messages:[{role:"user",content:g}]})});if(clearInterval(_),!s.ok)throw new Error(`API ${s.status}`);const i=buildHTML({grade:e,subject:t,q:a,week:n,comp:r,aiMode:!0,aiContent:(await s.json()).content.map(e=>"text"===e.type?e.text:"").join("").replace(/```html?|```/g,"").trim()});quill.clipboard.dangerouslyPasteHTML(i),autoSave(),showToast("✓ AI lesson plan generated by Claude!")}catch(e){clearInterval(_),showToast("⚠ AI unavailable — using template instead."),generateTemplate()}finally{h.classList.remove("active"),v.disabled=!1}}function buildHTML({grade:e,subject:t,q:a,week:n,comp:s,aiMode:i=!1,aiContent:o=""}){const r=ksOf(e),d=document.getElementById("t-name").value||"[Teacher Name]",l=document.getElementById("t-school").value||"[School Name]",c=document.getElementById("t-section").value||"[Section]",p=document.getElementById("t-date").value||(new Date).toISOString().split("T")[0],m=document.getElementById("t-time").value||"07:30",u=document.getElementById("t-dur").value||"60 mins",g=new Date(p+"T00:00:00").toLocaleDateString("en-PH",{year:"numeric",month:"long",day:"numeric"}),h=document.getElementById("tog-diverse").checked,v=document.getElementById("tog-lr").checked,b=document.getElementById("tog-values").checked,y=document.getElementById("sel-tier").value,f=document.getElementById("ai-g").checked,_=document.getElementById("ai-f").checked,w=document.getElementById("ai-s").checked,k=document.getElementById("ai-t").checked,S=f||_||w||k,E=[f&&"grammar/spelling",_&&"formatting",w&&"idea scaffolding",k&&"Fil-Eng translation"].filter(Boolean),I={normal:{bg:"",border:"",label:"",desc:""},hinay:{bg:"#eff6ff",border:"#93c5fd",label:"🔵 HINAY — Ease-In Mode (Hybrid Delivery)",desc:"Hybrid delivery is in effect. Printed Self-Learning Packets (SLPs) are available for remote learners. Distribute materials Monday; collect Friday. Record participation in the ADM Attendance Log."},hinga:{bg:"#fefce8",border:"#fbbf24",label:"🟡 HINGA — Check-In Mode (Home-Based Modular Learning)",desc:"Instruction is delivered via printed modules at home. A socio-emotional wellness check is embedded. Activate the 12-hour school call-tree protocol per DRRM guidelines."},hinto:{bg:"#fef2f2",border:"#fca5a5",label:"🔴 HINTO — Stop (Psychological First Aid Mode)",desc:"Regular academic lessons are SUSPENDED. This plan activates PFA and trauma-informed community check-in procedures. Teachers shall: (1) conduct home/phone wellness visits, (2) administer the PFA Needs Assessment Tool, (3) coordinate with the guidance office, barangay officials, and DSWD, (4) distribute basic needs referral forms. Academic resumption requires Division Office clearance."}}[y];let A="<div style=\"font-family:'Times New Roman',Times,serif;color:#111\">";return S&&(A+=`<div class="lp-ai"><strong>⚠ AI Use Declaration — DO No. 003, s. 2026</strong><br>This lesson plan was prepared with AI assistance for: <em>${E.join(", ")}</em>. All curricular content, pedagogical decisions, and student data were authored, verified, and remain the sole professional responsibility of the undersigned teacher. AI was used as a productivity tool and did not replace professional judgment.</div>`),"normal"!==y&&(A+=`<div class="lp-em" style="background:${I.bg};border:1px solid ${I.border}"><strong>${I.label}</strong><br>${I.desc}</div>`),A+=`<div class="lp-hdr"><div class="lp-t1">DEPARTMENT OF EDUCATION</div><div class="lp-t1" style="font-size:12pt">${l.toUpperCase()}</div><div class="lp-t2">ILAW LESSON PLAN</div><div class="lp-t3">Framework: DO No. 016, s. 2026 &nbsp;|&nbsp; Repeals DLL/DLP (DO 42, s. 2016)</div></div>`,A+=`<table class="lp-meta"><tr><td class="lbl">Teacher</td><td>${d}</td><td class="lbl">Grade &amp; Section</td><td>Grade ${e} — ${c}</td></tr><tr><td class="lbl">Subject</td><td>${t}</td><td class="lbl">Key Stage</td><td>${ksLabel(r)}</td></tr><tr><td class="lbl">Quarter / Week</td><td>Q${a} / Week ${n||"—"}</td><td class="lbl">Date</td><td>${g}</td></tr><tr><td class="lbl">Time / Duration</td><td>${m} &nbsp;|&nbsp; ${u}</td><td class="lbl">Competency Code</td><td>${s.code}</td></tr><tr><td class="lbl">Most Essential LC</td><td colspan="3">${s.text}</td></tr></table>`,i&&o?(A+=o,A+=buildSignature(d),A+="</div>",A):(A+='<div class="lp-sh">I — INTENTIONS</div>',A+='<div class="lp-ssh">Learning Objectives — CPA Framework</div>',A+=`<table class="lp-obj"><tr><td class="ol">Cognitive (C)</td><td>${s.C}</td></tr><tr><td class="ol">Psychomotor (P)</td><td>${s.P}</td></tr><tr><td class="ol">Affective (A)</td><td>${s.A}</td></tr></table>`,A+=`<div class="lp-ssh">Materials &amp; Learning Resources</div><div class="lp-body">Textbooks, SLMs, chalkboard / whiteboard. ${v?'<span class="lp-lr" style="display:inline"><strong>♻ Low-Resource:</strong> Replace laboratory equipment with household/recycled items (e.g., improvised materials, community garden items, cellphone flashlights). Coordinate with GPTA for sourcing.</span>':""}</div>`,h&&(A+=`<div class="lp-acc"><strong>🧩 Diverse Learner Accommodations (${ksLabel(r)})</strong><br>${getDiverseText(r)}</div>`),A+='<div class="lp-sh">L — LEARNING EXPERIENCE</div>',A+=`<div class="lp-ssh">Pre-Lesson / Motivation (5–10 mins)</div><div class="lp-body">${s.pre}</div>`,"hinto"===y?A+='<div class="lp-em" style="background:#fef2f2;border:1px solid #fca5a5"><strong>🔴 Academic instruction replaced by PFA Protocol</strong><br>See emergency tier note above. No academic flow steps are included during HINTO.</div>':(A+='<div class="lp-ssh">The Flow — Instructional Steps</div>',s.steps.forEach(e=>{let t=e.d;v&&(t+=' <em style="color:#166534;font-size:9pt">[Low-Resource: substitute lab materials with locally available alternatives.]</em>'),A+=`<div class="lp-step"><div class="lp-step-title">Step ${e.n}: ${e.t}</div><div class="lp-body">${t}</div><div class="lp-dp">🎯 Design Principles: ${e.dp.join(" · ")}</div></div>`})),"hinay"===y&&(A+='<div class="lp-em" style="background:#eff6ff;border:1px solid #93c5fd"><strong>🔵 Hinay Hybrid Supplement</strong><br>Printed SLPs are available for remote learners. Buddy system: pair in-person with remote learners. SLP schedule: distribute Monday / collect Friday. Record in ADM Attendance Log.</div>'),"hinga"===y&&(A+='<div class="lp-em" style="background:#fefce8;border:1px solid #fbbf24"><strong>🟡 Hinga Home-Based Supplement</strong><br>Modules distributed to households. Wellness check embedded at lesson start via phone call or printed wellness form. 12-hour school call-tree activated per DRRM protocol. Record completion in the HBLS Monitoring Form.</div>'),b&&(A+='<div class="lp-acc" style="border-color:#d97706;background:#fffbeb"><strong>🇵🇭 Values Integration</strong><br>Connect today\'s lesson to the DepEd Core Values (Maka-Diyos, Makatao, Makakalikasan, Makabansa). Prompt: How does what we learned today help us be better citizens / stewards of creation / caring community members?</div>'),A+='<div class="lp-sh">A — ASSESSING LEARNING</div>',A+=`<div class="lp-ssh">Assessment Task</div><div class="lp-body">${s.task}</div>`,A+=`<div class="lp-ssh">Rubric / Evaluation Criteria</div><div class="lp-body">${s.rubric}</div>`,1===r?(A+='<div class="lp-ssh">PACE Form — Performance and Competency Evaluation</div>',A+='<div class="lp-body" style="font-size:9pt;background:#f0fdf4;border:1px solid #86efac;border-radius:4px;padding:6px 10px;color:#166534"><strong>KS1 Policy:</strong> Formal written examinations are NOT conducted in Grades 1–3. Use the PACE Form below. Assessment aligns with BOSY literacy/numeracy diagnostics (CRLA and RMA).</div>',A+=`<table class="lp-pace" style="margin-top:8px"><thead><tr><th>Learner Name</th><th>Competency Observed</th><th>Teacher Notes</th><th>Status</th></tr></thead><tbody>${[1,2,3,4,5].map(e=>`<tr><td>${e}. ___________________</td><td>${s.text.substring(0,45)}…</td><td></td><td>Yes ☐ / Not Yet ☐</td></tr>`).join("")}</tbody></table>`,A+='<div class="lp-body" style="font-size:9pt;margin-top:6px;color:#555">BOSY Diagnostic: ☐ CRLA Assessed (Q1) &nbsp;|&nbsp; ☐ RMA Conducted (Q1) &nbsp;|&nbsp; Date: _____________</div>'):(A+=`<div class="lp-ssh">Grading Configuration — ${ksLabel(r)}</div>`,A+='<table class="lp-gt"><thead><tr><th>Component</th><th>Code</th><th>Weight</th><th>Raw Score</th><th>Weighted Score</th></tr></thead><tbody><tr><td>Written Works</td><td>WW</td><td><strong>20%</strong></td><td>___ / ___</td><td>___</td></tr><tr><td>Performance Tasks</td><td>PT</td><td><strong>50%</strong></td><td>___ / ___</td><td>___</td></tr><tr><td>Summative Tests &amp; Term Exams</td><td>ST</td><td><strong>30%</strong></td><td>___ / ___</td><td>___</td></tr><tr style="background:#eef3fa"><td colspan="2"><strong>Initial Grade</strong></td><td colspan="3">= WW(0.20) + PT(0.50) + ST(0.30) = ___</td></tr></tbody></table>',A+='<div class="lp-body" style="margin-top:6px;font-size:9.5pt;background:#f0f4f8;border:1px solid #d0dae8;border-radius:4px;padding:6px 10px"><strong>Transmutation Scale:</strong> Raw Score Percentage ≥ 70.00% → Transmuted Grade ≥ 75% (Passing). <em>Formula: Transmuted Grade = [(Raw Score ÷ Highest Possible Score) × 100] applied against the DepEd Transmutation Table.</em></div>'),A+='<div class="lp-sh">W — WAYS FORWARD</div>',A+=`<div class="lp-ssh">Remediation (ARAL)</div><div class="lp-body">${s.rem}</div>`,A+=`<div class="lp-ssh">Enrichment / Extension</div><div class="lp-body">${s.enr}</div>`,A+=`<div class="lp-ssh">Home / Community Learning Opportunity</div><div class="lp-body">${s.home}</div>`,v&&(A+='<div class="lp-lr"><strong>♻ Low-Resource Summary</strong><br>All standard laboratory materials have been substituted with locally available, recycled, or household alternatives as noted above. Teachers are encouraged to coordinate with GPTA, science clubs, and the barangay for sourcing. Document all material substitutions in the Weekly Home Learning Plan.</div>'),A+=buildSignature(d)+"</div>",A)}function buildSignature(e){return`<table class="lp-sig"><tr><td><div style="border-top:1px solid #333;padding-top:4px;margin-top:30px;text-align:center">${e||"________________________________"}<br><em style="font-size:9pt;color:#666">Teacher Prepared</em></div></td><td><div style="border-top:1px solid #333;padding-top:4px;margin-top:30px;text-align:center">________________________________<br><em style="font-size:9pt;color:#666">School Head / Noted By</em></div></td></tr></table>`}function getDiverseText(e){return{1:"• Provide tactile / sensory materials for learners with learning differences.\n• Use Mother Tongue / Filipino language scaffolding for L2 learners.\n• Allow alternative responses: drawing, pointing, or verbal answers.\n• Seat learners with attention difficulties close to the teacher.\n• Use simplified visual instructions throughout.",2:"• Provide graphic organizers and concept maps for processing difficulties.\n• Allow extended time for task completion as needed.\n• Pair struggling learners with peer buddies during group work.\n• Offer simplified vocabulary lists for EAL learners.\n• Provide preferential seating and low-distraction environments.",3:"• Allow learners with learning disabilities to use digital note-taking tools.\n• Offer modified assessment formats (oral response, portfolio evidence).\n• Assign peer mentoring roles to advanced learners.\n• Provide tiered task difficulty within the same MELC.\n• Support advanced learners with supplementary research assignments.",4:"• Allow students with IEPs / support plans to use approved assistive technology.\n• Provide annotated references and study guides for learners needing support.\n• Assign advanced learners research extension or peer-teaching roles.\n• Coordinate with the guidance office and parents for learners with identified special needs.\n• Allow flexible submission formats for performance tasks."}[e]||"Provide differentiated support as appropriate for this Key Stage."}function buildGeneric(e,t,a,n){const s=t||"the Subject Area";return{code:`${(t||"XX").substring(0,2).toUpperCase()}${e}Q${a}-W${n||"X"}`,text:`Demonstrate mastery of ${s} competencies for Grade ${e}, Quarter ${a}, Week ${n||"—"}.`,C:`Recall and apply key ${s} concepts aligned to this week's learning targets.`,P:`Demonstrate skills and processes related to this week's ${s} competency using appropriate tools.`,A:`Show appreciation for the real-world relevance of ${s} knowledge in everyday life.`,pre:"Begin with a brief review of the previous lesson and connect prior knowledge to today's learning objectives. Pose a guiding question to focus learner attention.",steps:[{n:1,t:"Introduction and Motivation",d:"Present learning objectives. Motivate learners with a relevant real-world scenario, visual aid, or hands-on starter activity.",dp:["Clear goals","Scaffolding"]},{n:2,t:"Guided Practice",d:"Lead learners through examples and demonstrations, checking for understanding at each step. Use think-pair-share or structured questioning.",dp:["Active retrieval","Social Learning"]},{n:3,t:"Independent Practice",d:"Learners complete tasks or activities independently, applying what they have learned. Teacher circulates and provides targeted feedback.",dp:["Self-awareness and Metacognition","Checks for understanding"]}],task:"Formative assessment aligned to the competency above. May include written checks, performance tasks, or observation checklists depending on the Key Stage.",rubric:"Evaluated using the appropriate Key Stage rubric and grading configuration.",rem:"Provide additional guided practice and simplified materials. Conduct individual or small-group review during the ARAL remediation period.",enr:"Challenge advanced learners with an extension task connecting the competency to real-world applications or higher-order thinking.",home:"Encourage learners to observe or apply today's concepts in their home or community. Assign a brief reflection or drawing activity."}}